//defines a card
class Card implements Comparable<Card> {
    public int compareTo(Card other) {
        return other.value - this.value;
    }

    public String toString() {
        return rank + " of " + suit;
    }

    String suit;
    String rank;
    String[] detailsTop;
    String[] detailsBottom;
    int value;
}

